import React, { useEffect} from 'react'
import { toast } from 'react-hot-toast';
import { useNavigate } from 'react-router-dom';


const MyBookings = () => {

    const navigate = useNavigate();
    let data;
    let outputArr=[];
    const viewBookings = async () => {
        try {
            //get user info first
            const res = await fetch('/getUser', {
                method: "GET",
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",

                },
                credentials: "include"
            });

            const data = await res.json();

            // saving order into this user
            const { email } = data;
            const refrence_id=urlElements[1];
            const {serviceType,duration,price}=JSON.parse(window.localStorage.getItem('userServiceCart'));
            
            const response = await fetch('/saveBooking', {
                method: "POST",
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({
                    email,
                    refrence_id,
                    serviceType,
                    duration,
                    price
                })
            });


            if(response.status===409){
                return;
            }


        } catch (error) {
            console.log(error);
        }

    }

    useEffect(() => {
        viewBookings();
    }, [])


    return (
        <div className='flex justify-center items-center text-white text-3xl h-screen '>
        {
          outputArr.length===0?<p>No Data</p>:<p>Data found</p>
        }
        </div>
    )
}

export default MyBookings
